const payload = JsonUtils.readJsonFromFile1('AdditionalBasicDetails_Flipkart');
const { appId, txnId } = await freshFkAppWithOffer(this, payload);
await verifySqlAfterAdditionalDetails(this, appId, txnId, {
    affluence_score:        'H',       // String14 → "H"
    cremo_bucket:           '5',       // String13 → "5" (string)
    emi_bucket:             '3',       // String12 → "3" (string)
    account_age:            250,       // Integer05 → 250 (integer)
    add_age:                12,        // Integer06 → 12 (integer)
    add_numericals:         10,        // Integer07 → 10 (integer)
    add_char:               120,       // Integer08 → 120 (integer)
    freq_delivered_pincode: 560001,    // Integer09 → 560001 (integer)
    recent_pincode:         '560034',  // String19 → "560034" (string)
    fk_bnpl_emi:            '1',       // Flag04 → "1" (string)
});

const base    = JsonUtils.readJsonFromFile1('AdditionalBasicDetails_Flipkart');
const payload = await JsonUtils.modifyPayload({ 'additional_partner_data.fk_bnpl_emi': '1' }, base);
const { appId, txnId } = await freshFkAppWithOffer(this, payload);
await verifySqlAfterAdditionalDetails(this, appId, txnId, { fk_bnpl_emi: '1' });

const base    = JsonUtils.readJsonFromFile1('AdditionalBasicDetails_Flipkart');
const payload = await JsonUtils.modifyPayload({ 'additional_partner_data.fk_bnpl_emi': undefined }, base);
