const { appId, additionalRes } = await freshFkAppWithOffer(this, payload);
expect(additionalRes.status, 'Additional Details HTTP status').to.equal(200);
// Locate OMNI_HC vendor log row for this app.
let omniHcSpare = null, omniHcRow = null;
for (let attempt = 1; attempt <= 8; attempt++) {
    const rawVendorRows = await queryWithRetry(
        'SELECT * FROM services.underwriting_vendor_transaction_log WHERE requestId = ? ORDER BY id DESC LIMIT 20',
        [appId]
    );
    for (const row of (rawVendorRows || []).map(parseRow)) {
        const spare = extractOmniHcSpare(row);
        if (spare) { omniHcRow = row; omniHcSpare = spare; break; }
    }
    if (omniHcSpare) break;
    await new Promise(res => setTimeout(res, 2000));
}
const found   = !!omniHcSpare;
const actual  = found ? getSlot(omniHcSpare, slot) : undefined;
const visible = actual !== undefined;
const summary = !found
    ? 'OMNI_HC vendor log not found (offer never reached Approved — inconclusive)'
    : visible
        ? `VISIBLE — slot ${slot} = ${JSON.stringify(actual)}`
        : `NOT VISIBLE — slot ${slot} absent (value silently dropped)`;
console.log(`\n  ${C}[Vendor Log Visibility] additional_partner_data.${field} sent ${JSON.stringify(badValue)} → ${summary}${X}`);
addContext(this, {
    title: `Vendor Log Visibility — ${field} = ${JSON.stringify(badValue)}`,
    value: { field, slot, sentValue: badValue, vendorLogRowFound: found,
             vendorLogValue: actual ?? null, visible, summary,
             raw_input: omniHcRow?.input || null },
});
if (found) {
    if (expected === undefined) {
        expect(actual, `${field} sent ${JSON.stringify(badValue)} — must NOT appear in vendor log [${slot}] (cast fails, value dropped)`).to.be.undefined;
    } else {
        expect(actual, `${field} sent ${JSON.stringify(badValue)} — must appear verbatim in vendor log [${slot}]`).to.equal(expected);
    }
} else {
    console.log(`  ${Y}⚠ Skipping assertion — vendor log row not found for appId=${appId}${X}`);
